import os
import boto3
import pickle
import json
import urllib.request
import tempfile
from pathlib import Path

class ModelLoader:
    def __init__(self):
        self.model_path = os.environ.get('MODEL_PATH', 's3://models/latest')
        self.model = None
        self.storage_type = self._detect_storage_type()
        
    def _detect_storage_type(self):
        if self.model_path.startswith('s3://'):
            return 's3'
        elif self.model_path.startswith('gs://'):
            return 'gcs'
        elif self.model_path.startswith('http://') or self.model_path.startswith('https://'):
            return 'http'
        else:
            return 'local'
    
    def load_model(self):
        if self.storage_type == 's3':
            return self._load_from_s3()
        elif self.storage_type == 'gcs':
            return self._load_from_gcs()
        elif self.storage_type == 'http':
            return self._load_from_http()
        else:
            return self._load_from_local()
    
    def _load_from_s3(self):
        s3_client = boto3.client('s3')
        bucket = self.model_path.split('/')[2]
        key = '/'.join(self.model_path.split('/')[3:])
        
        with tempfile.NamedTemporaryFile(delete=False, suffix='.pkl') as tmp_file:
            s3_client.download_file(bucket, key, tmp_file.name)
            with open(tmp_file.name, 'rb') as f:
                self.model = pickle.load(f)
            os.unlink(tmp_file.name)
        
        return self.model
    
    def _load_from_gcs(self):
        from google.cloud import storage
        
        bucket_name = self.model_path.split('/')[2]
        blob_name = '/'.join(self.model_path.split('/')[3:])
        
        client = storage.Client()
        bucket = client.bucket(bucket_name)
        blob = bucket.blob(blob_name)
        
        with tempfile.NamedTemporaryFile(delete=False, suffix='.pkl') as tmp_file:
            blob.download_to_filename(tmp_file.name)
            with open(tmp_file.name, 'rb') as f:
                self.model = pickle.load(f)
            os.unlink(tmp_file.name)
        
        return self.model
    
    def _load_from_http(self):
        with tempfile.NamedTemporaryFile(delete=False, suffix='.pkl') as tmp_file:
            urllib.request.urlretrieve(self.model_path, tmp_file.name)
            with open(tmp_file.name, 'rb') as f:
                self.model = pickle.load(f)
            os.unlink(tmp_file.name)
        
        return self.model
    
    def _load_from_local(self):
        with open(self.model_path, 'rb') as f:
            self.model = pickle.load(f)
        
        return self.model
    
    def get_latest_version(self):
        if self.storage_type == 's3':
            return self._get_latest_s3_version()
        elif self.storage_type == 'gcs':
            return self._get_latest_gcs_version()
        else:
            return self.model_path
    
    def _get_latest_s3_version(self):
        s3_client = boto3.client('s3')
        bucket = self.model_path.split('/')[2]
        prefix = '/'.join(self.model_path.split('/')[3:-1])
        
        response = s3_client.list_objects_v2(Bucket=bucket, Prefix=prefix)
        
        if 'Contents' in response:
            latest = sorted(response['Contents'], key=lambda x: x['LastModified'], reverse=True)[0]
            return f"s3://{bucket}/{latest['Key']}"
        
        return self.model_path
    
    def _get_latest_gcs_version(self):
        from google.cloud import storage
        
        bucket_name = self.model_path.split('/')[2]
        prefix = '/'.join(self.model_path.split('/')[3:-1])
        
        client = storage.Client()
        bucket = client.bucket(bucket_name)
        blobs = list(bucket.list_blobs(prefix=prefix))
        
        if blobs:
            latest = sorted(blobs, key=lambda x: x.updated, reverse=True)[0]
            return f"gs://{bucket_name}/{latest.name}"
        
        return self.model_path


class InferenceService:
    def __init__(self):
        self.loader = ModelLoader()
        self.model = None
        
    def startup(self):
        latest_model_path = self.loader.get_latest_version()
        self.loader.model_path = latest_model_path
        self.model = self.loader.load_model()
        print(f"Model loaded from: {latest_model_path}")
        
    def predict(self, data):
        if self.model is None:
            raise RuntimeError("Model not loaded")
        
        return self.model.predict(data)


if __name__ == '__main__':
    service = InferenceService()
    service.startup()
    
    print("Inference service ready")